-- Remove BASIC from public sale and keep it only as legacy/internal recognition.
-- Execute after deploying backend code that removes BASIC from public catalogs.

UPDATE subscription_plan_price
SET active = FALSE, updated_at = NOW()
WHERE upper(plan_code) = 'BASIC';

-- New public prices from July 2026 commercial structure.
-- Venezuela is intentionally priced in USD.
ON CONFLICT (plan_code, country_code, billing_cycle) DO UPDATE SET
    currency = EXCLUDED.currency,
    amount = EXCLUDED.amount,
    active = EXCLUDED.active,
    updated_at = NOW();
